import * as t from "io-ts";
import { TokenRecipientEntryItem } from "./tokenRecipientEntryItem";
import { SupportedTokenRecipientEntryItem } from "./supportedTokenRecipientEntryItem";
import { UnsupportedTokenRecipientEntryItem } from "./unsupportedTokenRecipientEntryItem";

export const TokenData = t.intersection([
  TokenRecipientEntryItem,
  SupportedTokenRecipientEntryItem,
  UnsupportedTokenRecipientEntryItem,
]);

export type TokenData = t.TypeOf<typeof TokenData>;
